import { Hono } from 'hono';
import bcrypt from 'bcrypt';

const app = new Hono();

app.post('/register', async (c) => {
  const { email, password } = c.req.valid('json');

  // Validate email format
  if (!email.includes('@')) {
    return c.json({ error: 'Invalid email format' }, 400);
  }

  // Hash the password
  const hashedPassword = await bcrypt.hash(password, 10);

  // Insert into users table (assuming a function `insertUser` exists)
  try {
    const userId = await insertUser(email, hashedPassword);
    return c.json({ userId }, 201);
  } catch (error) {
    return c.json({ error: 'Failed to register user' }, 500);
  }
});

export default app;

import { z } from 'zod';

const emailSchema = z.string().email();
const passwordSchema = z.string().min(8);

export const registerSchema = z.object({
  email: emailSchema,
  password: passwordSchema,
});

export type RegisterInput = z.infer<typeof registerSchema>;

import { sql } from 'slonik';

export async function insertUser(email: string, hashedPassword: string) {
  const pool = await getPool(); // Assume this function exists and returns a Slonik pool
  const result = await pool.query(sql`
    INSERT INTO users (email, password)
    VALUES (${email}, ${hashedPassword})
    RETURNING id;
  `);
  return result.rows[0].id;
}

import { Pool } from 'slonik';

export async function getPool() {
  // Assume this function exists and returns a Slonik pool
  const connection = await new Pool('your_database_connection_string');
  return connection;
}

